// HannahServiceServer is the server API for HannahService service.
// All implementations must embed UnimplementedHannahServiceServer
// for forward compatibility.
type HannahServiceServer interface {
	// --- User Registry ---
	GetUsers(context.Context, *GetUsersRequest) (*GetUsersResponse, error)
	GetUser(context.Context, *GetUserRequest) (*UserResponse, error)
	LinkAccount(context.Context, *LinkAccountRequest) (*StatusResponse, error)
	UnlinkAccount(context.Context, *UnlinkAccountRequest) (*StatusResponse, error)
	SetTrustLevel(context.Context, *SetTrustLevelRequest) (*StatusResponse, error)
	SetSystemMessages(context.Context, *SetSystemMessagesRequest) (*StatusResponse, error)
	// Enable/disable an automation service (e.g. "telegram_autoresponder") for a user.
	// Pushes a live update to any connected AutomationConnect stream registered for it.
	SetAutomation(context.Context, *SetAutomationRequest) (*StatusResponse, error)
	Login(context.Context, *LoginRequest) (*UserResponse, error)
	// --- User-Verwaltung (Admin-UI, #27 Phase 6) ---
	CreateUser(context.Context, *CreateUserRequest) (*CreateUserResponse, error)
	UpdateUser(context.Context, *UpdateUserRequest) (*StatusResponse, error)
	DeleteUser(context.Context, *DeleteUserRequest) (*StatusResponse, error)
	// Residents (Roomies/Guests/Pets) aus dem ioBroker-Adapter-Cache — fürs "Resident verknüpfen"-Dropdown.
	GetResidents(context.Context, *Empty) (*GetResidentsResponse, error)
	// --- Device Control Menu ---
	// Returns all rooms and devices with current state — for building control menus.
	GetDevices(context.Context, *Empty) (*GetDevicesResponse, error)
	// Directly set a device state (bypasses NLU). Trust level check is done by the caller.
	ControlDevice(context.Context, *ControlDeviceRequest) (*StatusResponse, error)
	// --- Control ---
	// Submit a plain-text command; Hannah processes it through NLU and returns the answer.
	SubmitText(context.Context, *SubmitTextRequest) (*SubmitTextResponse, error)
	// Submit a voice message (OGG/Opus bytes); Hannah does STT → NLU → TTS and returns the result.
	SubmitVoice(context.Context, *SubmitVoiceRequest) (*SubmitVoiceResponse, error)
	// Send a TTS announcement to one satellite or all ("all").
	Announce(context.Context, *AnnounceRequest) (*StatusResponse, error)
	// Send a notification from ioBroker to Hannah. Returns ok=true when queued.
	// direct=true: skip LLM reformulation. severity: "alert"|"notify"|"info".
	Notify(context.Context, *AgentNotification) (*StatusResponse, error)
	// List all known satellites (DB + live status merged).
	GetSatellites(context.Context, *Empty) (*GetSatellitesResponse, error)
	// --- Satellites (Admin-UI, #27 Phase 2) ---
	SetSatelliteRoom(context.Context, *SetSatelliteRoomRequest) (*StatusResponse, error)
	SetSatelliteDisplayName(context.Context, *SetSatelliteDisplayNameRequest) (*StatusResponse, error)
	// Assign a satellite to a Person (User), independent of its room. #31
	SetSatelliteOwner(context.Context, *SetSatelliteOwnerRequest) (*StatusResponse, error)
	// Delete existing satellite
	DeleteSatellite(context.Context, *DeleteSatelliteRequest) (*StatusResponse, error)
	// --- Rooms/Groups (Admin-UI, #27 Phase 1) ---
	GetRooms(context.Context, *Empty) (*GetRoomsResponse, error)
	GetGroups(context.Context, *Empty) (*GetGroupsResponse, error)
	CreateGroup(context.Context, *CreateGroupRequest) (*StatusResponse, error)
	UpdateGroup(context.Context, *UpdateGroupRequest) (*StatusResponse, error)
	DeleteGroup(context.Context, *DeleteGroupRequest) (*StatusResponse, error)
	SetGroupRooms(context.Context, *SetGroupRoomsRequest) (*StatusResponse, error)
	// --- Triggers (Admin-UI, #28) ---
	GetTriggers(context.Context, *Empty) (*GetTriggersResponse, error)
	CreateTrigger(context.Context, *CreateTriggerRequest) (*StatusResponse, error)
	UpdateTrigger(context.Context, *UpdateTriggerRequest) (*StatusResponse, error)
	DeleteTrigger(context.Context, *DeleteTriggerRequest) (*StatusResponse, error)
	// --- Alarms (Wecker, #4) ---
	GetAlarms(context.Context, *Empty) (*GetAlarmsResponse, error)
	CreateAlarm(context.Context, *CreateAlarmRequest) (*CreateAlarmResponse, error)
	UpdateAlarm(context.Context, *UpdateAlarmRequest) (*StatusResponse, error)
	DeleteAlarm(context.Context, *DeleteAlarmRequest) (*StatusResponse, error)
	// --- Settings (Admin-UI, #27 Phase 5) ---
	// CreateSetting/DeleteSetting wurden mit #115 entfernt: ble.tags/cars haben jetzt
	// eigene Modelle+CRUD (unten), nlu/iobroker.state_names/llm.system_prompt sind immer
	// vorab bekannt/geseedet — es gibt keinen verbleibenden Bedarf, neue Settings anzulegen.
	GetSettings(context.Context, *Empty) (*GetSettingsResponse, error)
	UpdateConfig(context.Context, *UpdateConfigRequest) (*StatusResponse, error)
	// --- BLE Tags (Admin-UI, #115 — eigenes Modell statt Settings-JSON-Blob) ---
	GetBleTags(context.Context, *Empty) (*GetBleTagsResponse, error)
	CreateBleTag(context.Context, *CreateBleTagRequest) (*CreateBleTagResponse, error)
	UpdateBleTag(context.Context, *UpdateBleTagRequest) (*StatusResponse, error)
	DeleteBleTag(context.Context, *DeleteBleTagRequest) (*StatusResponse, error)
	// --- Cars (Admin-UI, #115 — eigenes Modell + user_to_car-Pivot statt Settings-JSON-Blob) ---
	GetCars(context.Context, *Empty) (*GetCarsResponse, error)
	CreateCar(context.Context, *CreateCarRequest) (*CreateCarResponse, error)
	UpdateCar(context.Context, *UpdateCarRequest) (*StatusResponse, error)
	DeleteCar(context.Context, *DeleteCarRequest) (*StatusResponse, error)
	// --- Car state (Live-VW-Connect-Status, unabhängig von der Car-Konfiguration oben) ---
	// Returns the current cached car state (available=false if no data received yet).
	GetCarState(context.Context, *Empty) (*CarStateResponse, error)
	// Returns all tracked car states (one per configured car).
	GetAllCarStates(context.Context, *Empty) (*GetAllCarStatesResponse, error)
	// --- Event stream ---
	// Opens a server-side stream; Hannah pushes events as they occur.
	// Pass event_types to filter (empty = all events).
	// Known event types: "car.parked", "resident.arrived", "resident.departed", "satellite.firmware"
	SubscribeEvents(*EventFilter, grpc.ServerStreamingServer[HannahEvent]) error
	// --- Firmware Manager ---
	// Trigger an immediate OTA update for a satellite (bypasses residents check).
	TriggerFirmwareUpdate(context.Context, *TriggerFirmwareUpdateRequest) (*StatusResponse, error)
	// --- Wakeword Capture ---
	// Put a satellite in audio-capture mode for wakeword training data collection.
	// While captured: wakeword detection is suspended, speaker is muted, DND is active.
	// Hannah relays raw PCM chunks from the satellite to the collector via StreamSatelliteAudio.
	// The stream stays open until the collector disconnects; Hannah then auto-releases the satellite.
	RequestSatelliteCapture(context.Context, *SatelliteCaptureRequest) (*SatelliteCaptureResponse, error)
	ReleaseSatelliteCapture(context.Context, *SatelliteCaptureRequest) (*StatusResponse, error)
	StreamSatelliteAudio(*SatelliteCaptureRequest, grpc.ServerStreamingServer[SatelliteAudioChunk]) error
	// Play a plink sound on the satellite, then hold virtual PTT for record_duration seconds.
	// Returns after PTT is released — Collector calls this in a loop for guided hey-hannah collection.
	TriggerPlink(context.Context, *TriggerPlinkRequest) (*StatusResponse, error)
	// --- Satellite Proxy (Go gRPC proxy) ---
	// Bidirectional keepalive stream. Proxy sends heartbeats; Hannah sends TTS
	// audio commands back (for announcements). While this stream is open, Hannah
	// disables its own UDP server. If the stream drops, Hannah re-enables UDP.
	RegisterProxy(grpc.BidiStreamingServer[ProxyHeartbeat, ProxyCommand]) error
	// Submit a complete satellite audio session for processing.
	// Hannah runs the full pipeline (STT → NLU → TTS → MQTT status) and returns
	// the result so the proxy can play TTS audio back to the satellite.
	SubmitSatelliteAudio(context.Context, *SubmitSatelliteAudioRequest) (*SubmitSatelliteAudioResponse, error)
	// Notify Hannah that a satellite registered or disconnected via the proxy.
	// Hannah updates its room registry (hannah/rooms MQTT) immediately.
	NotifySatelliteRegistered(context.Context, *SatelliteRegistration) (*StatusResponse, error)
	NotifySatelliteGone(context.Context, *SatelliteRegistration) (*StatusResponse, error)
	// --- Satellite Provisioning ---
	// Called by the ioBroker adapter before WebFlash to pre-register a seed + display name + room.
	// When the satellite first connects with that seed, Hannah links serial → pre-config and clears the seed.
	ProvisionSatellite(context.Context, *ProvisionSatelliteRequest) (*StatusResponse, error)
	// --- Speaker Enrollment ---
	EnrollVoiceprint(context.Context, *EnrollVoiceprintRequest) (*StatusResponse, error)
	// --- Timer Service ---
	// Bidirectional stream between the Hannah Timer Service and Hannah Core.
	// The Timer Service initiates the connection; if Hannah restarts, the service reconnects.
	// Hannah sends timer commands (create, cancel, list); the service fires events when timers expire.
	TimerConnect(grpc.BidiStreamingServer[TimerMessage, TimerCommand]) error
	// --- Timer Admin ---
	// Query and cancel timers independent of the TimerConnect stream — e.g. for an
	// Admin-UI or Telegram bot listing/cancelling a user's active timers.
	GetTimers(context.Context, *GetTimersRequest) (*GetTimersResponse, error)
	DeleteTimer(context.Context, *DeleteTimerRequest) (*StatusResponse, error)
	// --- ioBroker Agent ---
	// Single bidirectional stream between the HannahAgent ioBroker adapter and Hannah Core.
	// The adapter pushes state updates (device states, presence, text commands);
	// Hannah pushes device-control commands and on-demand state-subscription requests back.
	// The adapter initiates the connection; if Hannah restarts, the adapter reconnects.
	AgentConnect(grpc.BidiStreamingServer[AgentMessage, AgentCommand]) error
	// --- Automations ---
	// Bidirectional stream for external automation services (e.g. telegram_autoresponder).
	// The service sends an AutomationRegister identifying itself, then Hannah replies with
	// an AutomationSnapshot (all users with it currently enabled) followed by live
	// AutomationStateChanged deltas as users toggle it via SetAutomation/voice.
	// Chosen over SubscribeEvents so a reconnecting service always gets a fresh snapshot
	// instead of missing state changes that happened while it was offline.
	AutomationConnect(grpc.BidiStreamingServer[AutomationMessage, AutomationCommand]) error
	mustEmbedUnimplementedHannahServiceServer()
}

